import React, { useState } from "react";

const predefinedIngredients = [
  "Chicken", "Beef", "Pork", "Fish", "Tofu", "Eggs"
];

const IngredientSelector = ({ selectedIngredients, setSelectedIngredients, fetchRecipes }) => {
  const [customIngredient, setCustomIngredient] = useState("");

  const handleCheckboxChange = (ingredient) => {
    if (selectedIngredients.includes(ingredient)) {
      setSelectedIngredients(selectedIngredients.filter(item => item !== ingredient));
    } else {
      setSelectedIngredients([...selectedIngredients, ingredient]);
    }
  };

  const addCustomIngredient = () => {
    const trimmed = customIngredient.trim();
    if (trimmed && !selectedIngredients.includes(trimmed)) {
      setSelectedIngredients([...selectedIngredients, trimmed]);
      setCustomIngredient("");
    }
  };

  return (
    <div className="ingredient-section">
      <h2>What's in your fridge?</h2>

      <div className="checkbox-group">
        {predefinedIngredients.map((item, idx) => (
          <label key={idx} className="checkbox-label">
            <input
              type="checkbox"
              checked={selectedIngredients.includes(item)}
              onChange={() => handleCheckboxChange(item)}
            /> {item}
          </label>
        ))}
      </div>

      <div className="input-group">
        <input
          type="text"
          value={customIngredient}
          onChange={(e) => setCustomIngredient(e.target.value)}
          placeholder="Add other ingredients"
        />
        <button onClick={addCustomIngredient} className="main-button small">Add</button>
      </div>

      <div style={{ textAlign: "right" }}>
        <button onClick={fetchRecipes} className="main-button">Generate Recipes</button>
      </div>
    </div>
  );
};

export default IngredientSelector;
